import { useState, useEffect } from 'react';
import { ChevronRight, FileText, Code, Book } from 'lucide-react';

function SidebarNav({ categories, activePath, isCollapsed, onToggle }) {
  const [expandedSections, setExpandedSections] = useState(() => {
    const saved = localStorage.getItem('docs-nav-expanded');
    return saved ? JSON.parse(saved) : categories.map(c => c.id);
  });

  useEffect(() => {
    localStorage.setItem('docs-nav-expanded', JSON.stringify(expandedSections));
  }, [expandedSections]);

  const toggleSection = (id) => {
    setExpandedSections(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  if (isCollapsed) return null;

  return (
    <nav className="docs-sidebar">
      {categories.map(category => (
        <NavCategory
          key={category.id}
          title={category.title}
          icon={getIcon(category.icon)}
          isExpanded={expandedSections.includes(category.id)}
          onToggle={() => toggleSection(category.id)}
        >
          {category.children.map(item => (
            <NavLink
              key={item.path}
              href={item.path}
              title={item.title}
              isActive={activePath === item.path}
              badge={item.badge}
            />
          ))}
        </NavCategory>
      ))}
    </nav>
  );
}

function ContextualPanel({ headings, relatedTopics, codeRefs }) {
  const [activeId, setActiveId] = useState('');

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            setActiveId(entry.target.id);
          }
        });
      },
      { rootMargin: '-100px 0px -70% 0px' }
    );

    headings.forEach(heading => {
      const el = document.getElementById(heading.id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, [headings]);

  return (
    <aside className="contextual-panel">
      <TableOfContents headings={headings} activeId={activeId} />
      <RelatedTopics topics={relatedTopics} />
      {codeRefs.length > 0 && <CodeReferences references={codeRefs} />}
    </aside>
  );
}

async function performSearch(query) {
  const searchRequest = {
    query,
    context: {
      currentPath: window.location.pathname,
      recentSearches: getRecentSearches(),
      userPreferences: getUserPreferences()
    },
    filters: {
      categories: selectedCategories,
      contentTypes: ['guide', 'api', 'tutorial'],
      includeCode: true
    }
  };

  if (minimaxApiKey) {
    // AI-powered semantic search via Minimax
    const response = await minimaxSearch(searchRequest);
    return parseSemanticResults(response);
  } else {
    // Fallback to simple text search
    return basicSearch(searchRequest);
  }
}

async function minimaxSearch(request) {
  const response = await fetch('https://api.minimax.chat/v1/search', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${minimaxApiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'minimax-search',
      query: request.query,
      documents: getIndexedDocuments(),
      options: {
        semantic: true,
        highlight: true,
        max_results: 10
      }
    })
  });
  return response.json();
}

function ThemeProvider({ children }) {
  const [theme, setTheme] = useState(() => {
    const saved = localStorage.getItem('docs-theme-preference');
    return saved || 'system';
  });

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('docs-theme-preference', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => {
      if (prev === 'light') return 'dark';
      if (prev === 'dark') return 'system';
      return 'light';
    });
  };

  return (
    <ThemeContext.Provider value={{ theme, setTheme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

function useKeyboardShortcuts(isModalOpen) {
  useEffect(() => {
    if (isModalOpen) return;

    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        openSearchModal();
      }
      if ((e.metaKey || e.ctrlKey) && e.key === '[') {
        e.preventDefault();
        navigateToPreviousTopic();
      }
      if ((e.metaKey || e.ctrlKey) && e.key === ']') {
        e.preventDefault();
        navigateToNextTopic();
      }
      if (e.key === 't' && !isInputFocused()) {
        e.preventDefault();
        toggleTheme();
      }
    };

    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [isModalOpen]);
}

function CodePlayground({ initialCode, language, dependencies }) {
  const [code, setCode] = useState(initialCode);
  const [output, setOutput] = useState('');
  const [isRunning, setIsRunning] = useState(false);

  const runCode = async () => {
    setIsRunning(true);
    try {
      const result = await executeInSandbox(code, language, dependencies);
      setOutput(result);
    } catch (error) {
      setOutput('Error: ' + error.message);
    }
    setIsRunning(false);
  };

  return (
    <div className="code-playground">
      <div className="playground-editor">
        <SyntaxHighlighter language={language}>
          {code}
        </SyntaxHighlighter>
        <textarea
          value={code}
          onChange={(e) => setCode(e.target.value)}
          className="playground-input"
        />
      </div>
      <div className="playground-toolbar">
        <button onClick={runCode} disabled={isRunning}>
          {isRunning ? 'Running...' : 'Run'}
        </button>
        <button onClick={() => setCode(initialCode)}>Reset</button>
        <button onClick={copyToClipboard}>Copy</button>
      </div>
      {output && <pre className="playground-output">{output}</pre>}
    </div>
  );
}

function TopicNavigation({ currentPath, navigationTree }) {
  const flatNav = flattenNavigation(navigationTree);
  const currentIndex = flatNav.findIndex(item => item.path === currentPath);

  const previous = currentIndex > 0 ? flatNav[currentIndex - 1] : null;
  const next = currentIndex < flatNav.length - 1 ? flatNav[currentIndex + 1] : null;

  return (
    <nav className="topic-navigation">
      <div className="nav-prev">
        {previous && (
          <Link to={previous.path} className="nav-link">
            <span className="nav-label">Previous</span>
            <span className="nav-title">
              <ChevronLeft size={16} />
              {previous.title}
            </span>
          </Link>
        )}
      </div>
      <div className="nav-next">
        {next && (
          <Link to={next.path} className="nav-link">
            <span className="nav-label">Next</span>
            <span className="nav-title">
              {next.title}
              <ChevronRight size={16} />
            </span>
          </Link>
        )}
      </div>
    </nav>
  );
}
